import { Link, useNavigate } from 'react-router-dom';
import { useState, useEffect } from 'react';
import Card from '../components/Card';
import Button from '../components/Button';

const domains = [
  { title: 'AI & ML', description: 'Machine learning models, data pipelines and intelligent systems.' },
  { title: 'Web Development', description: 'Frontend, backend, and full-stack app delivery.' },
  { title: 'Cloud & DevOps', description: 'Cloud services automation, CI/CD, and infrastructure as code.' },
  { title: 'Cybersecurity', description: 'Secure design, risk management, and defensive tools.' }
];

export default function DomainsPage() {
  const navigate = useNavigate();

  const [selectedDomain, setSelectedDomain] = useState(null);
  const [showDomains, setShowDomains] = useState(true);

  // ✅ Load selected domain
  useEffect(() => {
    const stored = localStorage.getItem("selectedDomain");
    if (stored) {
      setSelectedDomain(stored);
      setShowDomains(false); // hide domains initially
    }
  }, []);

  const formatUrl = (title) =>
    title.toLowerCase().replace(/&/g, 'and').replace(/\s+/g, '-');

  return (
    <div className="space-y-8">
      <Card title="Domain selection">

        {/* ✅ SHOW OPTIONS IF DOMAIN ALREADY SELECTED */}
        {!showDomains && selectedDomain && (
          <div className="text-center space-y-5 mb-6">

            <p className="text-lg font-semibold">
              You already selected a domain
            </p>

            <div className="flex justify-center gap-4">

              {/* Continue */}
              <Button onClick={() => navigate(`/roadmap/${selectedDomain}`)}>
                Continue
              </Button>

              {/* Change */}
              <Button variant="ghost" onClick={() => setShowDomains(true)}>
                Change Domain
              </Button>

            </div>

          </div>
        )}

        {/* ✅ SHOW DOMAIN LIST */}
        {showDomains && (
          <div className="grid gap-5 sm:grid-cols-2 lg:grid-cols-3">
            {domains.map((domain) => {
              const url = formatUrl(domain.title);

              return (
                <div
                  key={domain.title}
                  className="rounded-[2rem] border border-slate-300 bg-green-100 p-6 shadow-md cursor-pointer"
                  onClick={() => {
                    localStorage.setItem("selectedDomain", url);
                    localStorage.setItem("currentDay", 1);
                    localStorage.setItem("carryForward", "[]");
                    navigate(`/roadmap/${url}`);
                  }}
                >
                  <h3 className="text-xl font-semibold">
                    {domain.title}
                  </h3>

                  <p className="mt-3">
                    {domain.description}
                  </p>

                  <div className="mt-5 px-4 py-2 bg-gray-200 rounded-full inline-block">
                    Select path
                  </div>
                </div>
              );
            })}
          </div>
        )}

      </Card>
    </div>
  );
}
